INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('5e817d4a-bca3-442e-be39-93f237e411c9', $q$Customer Health Scores$q$, $q$Configurable scoring engine combining usage, support, billing and survey data to flag at-risk and thriving accounts.$q$, 0);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('5e817d4a-bca3-442e-be39-93f237e411c9', $q$Customer 360 Profile$q$, $q$Unified account view pulling CRM, billing, support and product usage data into one screen.$q$, 1);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('5e817d4a-bca3-442e-be39-93f237e411c9', $q$Automation & Playbooks$q$, $q$Trigger-based workflows that automatically create tasks, alerts and emails based on account behavior.$q$, 2);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('5e817d4a-bca3-442e-be39-93f237e411c9', $q$CustifyAI$q$, $q$AI-generated account summaries, risk signals and drafted customer communications.$q$, 3);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('5e817d4a-bca3-442e-be39-93f237e411c9', $q$Customer Portal$q$, $q$Branded, shared workspace for success plans, tasks and milestones with customers.$q$, 4);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('5e817d4a-bca3-442e-be39-93f237e411c9', $q$Onboarding Checklists$q$, $q$Structured templates to track new-customer implementation and time-to-value.$q$, 5);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('5e817d4a-bca3-442e-be39-93f237e411c9', $q$In-App Feedback Surveys$q$, $q$NPS/CSAT surveys triggered inside the product to feed into health scores.$q$, 6);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('5e817d4a-bca3-442e-be39-93f237e411c9', $q$Dashboards & Reporting$q$, $q$Retention, expansion, and CSM-productivity reporting for leadership.$q$, 7);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('5e817d4a-bca3-442e-be39-93f237e411c9', $q$Faster implementation (about four weeks) than enterprise-grade competitors like Gainsight$q$, 0);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('5e817d4a-bca3-442e-be39-93f237e411c9', $q$Deep, native integrations with common SaaS billing, CRM and support tools$q$, 1);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('5e817d4a-bca3-442e-be39-93f237e411c9', $q$GDPR-compliant, Germany-hosted data appeals to EU-based customers$q$, 2);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('5e817d4a-bca3-442e-be39-93f237e411c9', $q$No setup fees and dedicated onboarding support$q$, 3);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('5e817d4a-bca3-442e-be39-93f237e411c9', $q$No published self-serve pricing; requires a sales call to get a quote$q$, 0);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('5e817d4a-bca3-442e-be39-93f237e411c9', $q$Reporting and analytics customization is less extensive than category leader Gainsight$q$, 1);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('5e817d4a-bca3-442e-be39-93f237e411c9', $q$Built specifically for B2B SaaS, so less suited to non-subscription businesses$q$, 2);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('5e817d4a-bca3-442e-be39-93f237e411c9', $q$Smaller ecosystem of pre-built integrations than larger competitors$q$, 3);
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('5e817d4a-bca3-442e-be39-93f237e411c9', $q$What is Custify used for?$q$, $q$Custify is used by B2B SaaS customer success teams to track customer health, automate onboarding and renewal workflows, and identify churn risk and expansion opportunities.$q$, 0, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('5e817d4a-bca3-442e-be39-93f237e411c9', $q$How much does Custify cost?$q$, $q$Custify does not publish list pricing; costs are provided via custom quote based on seats, number of managed accounts, and workflow complexity.$q$, 1, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('5e817d4a-bca3-442e-be39-93f237e411c9', $q$Does Custify offer a free trial?$q$, $q$Custify is typically sold via demo and custom quote rather than self-serve signup, so prospective customers should request a demo to discuss trial or pilot options.$q$, 2, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('5e817d4a-bca3-442e-be39-93f237e411c9', $q$What integrations does Custify support?$q$, $q$Custify integrates with CRMs like Salesforce and HubSpot, support tools like Zendesk and Intercom, and billing platforms like Stripe and Chargebee.$q$, 3, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('5e817d4a-bca3-442e-be39-93f237e411c9', $q$Who are Custify's main competitors?$q$, $q$Gainsight, Totango, ChurnZero, Vitally, ClientSuccess and Planhat are commonly compared alternatives.$q$, 4, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('5e817d4a-bca3-442e-be39-93f237e411c9', $q$Is Custify suitable for small businesses?$q$, $q$Custify is aimed primarily at small-to-mid-market B2B SaaS companies with dedicated customer success teams rather than solo founders or very early-stage startups.$q$, 5, 'published');
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('5e817d4a-bca3-442e-be39-93f237e411c9', $q$Reducing SaaS churn$q$, $q$Customer success teams use health scores and automated playbooks to identify at-risk accounts before renewal.$q$, $q$B2B SaaS customer success teams$q$, 0);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('5e817d4a-bca3-442e-be39-93f237e411c9', $q$Onboarding and time-to-value tracking$q$, $q$CS teams use checklists and the customer portal to structure and speed up new-customer onboarding.$q$, $q$Onboarding and implementation teams$q$, 1);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('5e817d4a-bca3-442e-be39-93f237e411c9', $q$Expansion and upsell identification$q$, $q$CS and sales teams use usage data and health scores to identify accounts ready for upsell or cross-sell.$q$, $q$Customer success and account management$q$, 2);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('5e817d4a-bca3-442e-be39-93f237e411c9', $q$Custom$q$, $q$Contact sales$q$, $q$Custom / annual contract$q$, NULL, $q$["Tailored to company size, seats and workflow complexity","No setup fees","Guided ~4-week onboarding","Dedicated customer success manager"]$q$::jsonb, 0);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('5e817d4a-bca3-442e-be39-93f237e411c9', $q$overview$q$, $q$Overview$q$, 2, ARRAY[$q$Custify is a customer success platform built specifically for B2B SaaS companies, founded in 2017 by Philipp Wolf and headquartered in Munich, Germany. It consolidates product usage, billing, and support data into a single Customer 360 view so customer success managers can spot churn risk and expansion opportunities without juggling spreadsheets.$q$, $q$Rather than being a general-purpose CRM, Custify is purpose-built for the customer success workflow: health scoring, automated playbooks, onboarding tracking, and renewal management, sold via demo and custom quote rather than self-serve signup.$q$]::text[], 0);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('5e817d4a-bca3-442e-be39-93f237e411c9', $q$key-features$q$, $q$Key Features$q$, 2, ARRAY[$q$Custify's core is a configurable health-scoring engine that blends product usage, support tickets, survey feedback, and billing status into a single risk signal per account, paired with an automation and playbook builder that triggers tasks, alerts, and emails based on account behavior.$q$, $q$Supporting modules include onboarding checklists, in-app NPS and CSAT surveys, a branded customer portal for shared success plans, dashboards and reporting for retention and expansion metrics, and CustifyAI, which auto-generates account summaries and drafts customer communications.$q$]::text[], 1);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('5e817d4a-bca3-442e-be39-93f237e411c9', $q$pricing-overview$q$, $q$Pricing$q$, 2, ARRAY[$q$Custify does not publish self-serve pricing. Costs are determined through a custom quote based on the number of seats, managed customer accounts, and workflow complexity, following the same sales-led pricing model used by competitors like Gainsight and Totango.$q$, $q$The company advertises no setup fees and a roughly four-week guided onboarding process, positioning itself as faster and less costly to implement than enterprise-grade competitors.$q$]::text[], 2);
INSERT INTO tool_tag_links (tool_id, tag_id) VALUES ('5e817d4a-bca3-442e-be39-93f237e411c9', 'c296bd6a-c865-41d7-8807-5dce653dd3f5') ON CONFLICT DO NOTHING;
INSERT INTO tool_tag_links (tool_id, tag_id) VALUES ('5e817d4a-bca3-442e-be39-93f237e411c9', '96595ec7-e449-4fd5-803d-e73ba922c0ca') ON CONFLICT DO NOTHING;
INSERT INTO tool_tag_links (tool_id, tag_id) VALUES ('5e817d4a-bca3-442e-be39-93f237e411c9', '4137e3dc-5b54-4d6a-adfa-85ce8104e38f') ON CONFLICT DO NOTHING;
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('88c573c2-bcec-44cf-a9cb-80c691b977d7', $q$Journeys (Visual Workflow Builder)$q$, $q$Trigger-based, multi-step campaign builder spanning email, SMS, push and in-app messaging.$q$, 0);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('88c573c2-bcec-44cf-a9cb-80c691b977d7', $q$Data Pipelines$q$, $q$Customer data platform ingesting behavioral and profile data from apps, websites, CRMs and warehouses.$q$, 1);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('88c573c2-bcec-44cf-a9cb-80c691b977d7', $q$Multi-Channel Messaging$q$, $q$Send coordinated messages across email, SMS, push notifications and in-app/web messages.$q$, 2);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('88c573c2-bcec-44cf-a9cb-80c691b977d7', $q$Behavioral Segmentation$q$, $q$Build segments from any tracked event or attribute, not just static contact fields.$q$, 3);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('88c573c2-bcec-44cf-a9cb-80c691b977d7', $q$A/B Testing & Send-Time Optimization$q$, $q$Test message variants and automatically optimize delivery timing.$q$, 4);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('88c573c2-bcec-44cf-a9cb-80c691b977d7', $q$AI Agent$q$, $q$AI-assisted campaign drafting and natural-language customer segment summaries.$q$, 5);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('88c573c2-bcec-44cf-a9cb-80c691b977d7', $q$Broadcast Campaigns$q$, $q$One-off and recurring broadcast messaging alongside automated journeys.$q$, 6);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('88c573c2-bcec-44cf-a9cb-80c691b977d7', $q$Reporting & Revenue Attribution$q$, $q$Engagement analytics covering opens, clicks, conversions and revenue impact.$q$, 7);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('88c573c2-bcec-44cf-a9cb-80c691b977d7', $q$Granular, event-based segmentation beyond static contact lists$q$, 0);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('88c573c2-bcec-44cf-a9cb-80c691b977d7', $q$Multi-channel orchestration (email, SMS, push, in-app) from one workflow builder$q$, 1);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('88c573c2-bcec-44cf-a9cb-80c691b977d7', $q$More affordable entry pricing than Braze or Iterable for similar behavioral capabilities$q$, 2);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('88c573c2-bcec-44cf-a9cb-80c691b977d7', $q$Strong API and SDK support for developer-driven data instrumentation$q$, 3);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('88c573c2-bcec-44cf-a9cb-80c691b977d7', $q$Pricing scales quickly with profile and email volume$q$, 0);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('88c573c2-bcec-44cf-a9cb-80c691b977d7', $q$Steeper learning curve than simple email marketing tools due to data-model flexibility$q$, 1);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('88c573c2-bcec-44cf-a9cb-80c691b977d7', $q$No permanent free plan, only a 14-day trial$q$, 2);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('88c573c2-bcec-44cf-a9cb-80c691b977d7', $q$Advanced tiers (Premium/Enterprise) require custom sales negotiation for pricing$q$, 3);
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('88c573c2-bcec-44cf-a9cb-80c691b977d7', $q$What is Customer.io used for?$q$, $q$Customer.io is used to send behavior-triggered marketing and lifecycle messages across email, SMS, push and in-app channels based on real-time customer data.$q$, 0, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('88c573c2-bcec-44cf-a9cb-80c691b977d7', $q$How much does Customer.io cost?$q$, $q$Plans start at $100/month for the Essentials tier (5,000 profiles, 1M emails), with Standard, Premium and Enterprise tiers priced on custom profile and email volume.$q$, 1, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('88c573c2-bcec-44cf-a9cb-80c691b977d7', $q$Does Customer.io have a free plan?$q$, $q$No, but it offers a 14-day free trial on self-serve plans and a Startup Program discount for qualifying early-stage companies.$q$, 2, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('88c573c2-bcec-44cf-a9cb-80c691b977d7', $q$What channels can I send from Customer.io?$q$, $q$Email, SMS, push notifications, and in-app or on-site messaging, all orchestrated from a single workflow builder.$q$, 3, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('88c573c2-bcec-44cf-a9cb-80c691b977d7', $q$What are Customer.io's main alternatives?$q$, $q$Braze, Iterable, Klaviyo, ActiveCampaign and HubSpot are commonly compared alternatives.$q$, 4, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('88c573c2-bcec-44cf-a9cb-80c691b977d7', $q$Is Customer.io good for e-commerce?$q$, $q$Yes, though Klaviyo is more specialized for e-commerce; Customer.io is popular across both B2C and B2B SaaS use cases.$q$, 5, 'published');
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('88c573c2-bcec-44cf-a9cb-80c691b977d7', $q$Lifecycle and retention marketing$q$, $q$Automated email and multi-channel journeys to onboard, engage and retain users based on behavior.$q$, $q$Growth and lifecycle marketers$q$, 0);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('88c573c2-bcec-44cf-a9cb-80c691b977d7', $q$Behavioral triggers$q$, $q$Cart abandonment, feature-adoption nudges and onboarding sequences triggered by product events.$q$, $q$Product marketing and PLG teams$q$, 1);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('88c573c2-bcec-44cf-a9cb-80c691b977d7', $q$Multi-channel campaign orchestration$q$, $q$Coordinated email, SMS, push and in-app campaigns from a single workflow builder.$q$, $q$CRM and marketing operations teams$q$, 2);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('88c573c2-bcec-44cf-a9cb-80c691b977d7', $q$Essentials$q$, $q$$100/month$q$, $q$Monthly$q$, NULL, $q$["5,000 profiles","1 million emails/month","2 object types","Email and community support"]$q$::jsonb, 0);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('88c573c2-bcec-44cf-a9cb-80c691b977d7', $q$Standard$q$, $q$Custom$q$, $q$Monthly or annual$q$, NULL, $q$["Custom profile and email volume","Daily Routines","10 object types","Premium chat and email support"]$q$::jsonb, 1);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('88c573c2-bcec-44cf-a9cb-80c691b977d7', $q$Premium$q$, $q$From ~$1,000/month$q$, $q$Annual$q$, NULL, $q$["Best profile and email pricing","Elevated AI Agent limits","Dedicated customer success manager","Migration support"]$q$::jsonb, 2);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('88c573c2-bcec-44cf-a9cb-80c691b977d7', $q$Enterprise$q$, $q$Custom$q$, $q$Annual contract$q$, NULL, $q$["Dedicated hardware","Custom Agent limits","HIPAA compliance available","Negotiated volume pricing"]$q$::jsonb, 3);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('88c573c2-bcec-44cf-a9cb-80c691b977d7', $q$overview$q$, $q$Overview$q$, 2, ARRAY[$q$Customer.io is a customer engagement platform founded in 2012 by Colin Nederkoorn and headquartered in Portland, Oregon. It combines a customer data platform with a visual workflow builder so marketing and product teams can send behavior-triggered messages across email, SMS, push, and in-app channels.$q$, $q$The platform is aimed at teams that want segmentation based on real product behavior rather than static contact lists, making it popular with product-led growth companies and technically sophisticated marketing teams.$q$]::text[], 0);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('88c573c2-bcec-44cf-a9cb-80c691b977d7', $q$key-features$q$, $q$Key Features$q$, 2, ARRAY[$q$Journeys, Customer.io's workflow builder, lets teams create trigger-based, multi-step campaigns across email, SMS, push and in-app messaging, personalized with real-time customer attributes and event history, alongside A/B testing and send-time optimization.$q$, $q$Data Pipelines, the underlying customer data platform, ingests behavioral and profile data from apps, websites, CRMs and data warehouses, while a newer AI Agent feature can draft campaigns and summarize customer segments in natural language.$q$]::text[], 1);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('88c573c2-bcec-44cf-a9cb-80c691b977d7', $q$pricing-overview$q$, $q$Pricing$q$, 2, ARRAY[$q$Customer.io's Essentials plan starts at $100 per month for up to 5,000 profiles and 1 million emails. Standard and Premium tiers scale profile and email volume with custom pricing, with Premium commonly starting around $1,000 per month billed annually.$q$, $q$An Enterprise tier offers custom-negotiated pricing with dedicated infrastructure and HIPAA compliance. All self-serve plans include a 14-day free trial, and qualifying early-stage startups can apply for discounted pricing through the Startup Program.$q$]::text[], 2);
INSERT INTO tool_tag_links (tool_id, tag_id) VALUES ('88c573c2-bcec-44cf-a9cb-80c691b977d7', 'c296bd6a-c865-41d7-8807-5dce653dd3f5') ON CONFLICT DO NOTHING;
INSERT INTO tool_tag_links (tool_id, tag_id) VALUES ('88c573c2-bcec-44cf-a9cb-80c691b977d7', '96595ec7-e449-4fd5-803d-e73ba922c0ca') ON CONFLICT DO NOTHING;
INSERT INTO tool_tag_links (tool_id, tag_id) VALUES ('88c573c2-bcec-44cf-a9cb-80c691b977d7', '4137e3dc-5b54-4d6a-adfa-85ce8104e38f') ON CONFLICT DO NOTHING;
INSERT INTO tool_tag_links (tool_id, tag_id) VALUES ('88c573c2-bcec-44cf-a9cb-80c691b977d7', '610c2598-d057-4727-bf3b-e907b0daed7f') ON CONFLICT DO NOTHING;
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('0d4608fd-3411-46e9-b7bd-86e6765d726c', $q$Multi-Shape Annotation$q$, $q$Bounding boxes, polygons, polylines, points, cuboids and skeletons for varied labeling tasks.$q$, 0);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('0d4608fd-3411-46e9-b7bd-86e6765d726c', $q$Video Interpolation & Tracking$q$, $q$Automatic object tracking and frame interpolation across video sequences.$q$, 1);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('0d4608fd-3411-46e9-b7bd-86e6765d726c', $q$AI-Assisted Annotation$q$, $q$Model-assisted pre-labeling to speed up dataset creation.$q$, 2);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('0d4608fd-3411-46e9-b7bd-86e6765d726c', $q$3D Point Cloud Support$q$, $q$Annotation tools for LiDAR and 3D point-cloud data.$q$, 3);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('0d4608fd-3411-46e9-b7bd-86e6765d726c', $q$Dataset Import/Export$q$, $q$Support for COCO, YOLO, Pascal VOC, CVAT XML and other ML dataset formats.$q$, 4);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('0d4608fd-3411-46e9-b7bd-86e6765d726c', $q$Self-Hosted Deployment$q$, $q$Docker Compose deployment for full control over infrastructure and data.$q$, 5);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('0d4608fd-3411-46e9-b7bd-86e6765d726c', $q$Team Collaboration & RBAC$q$, $q$Project and task management with role-based access control.$q$, 6);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('0d4608fd-3411-46e9-b7bd-86e6765d726c', $q$Review & Quality Control$q$, $q$Built-in workflow for reviewing and verifying annotation accuracy.$q$, 7);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('0d4608fd-3411-46e9-b7bd-86e6765d726c', $q$Free and open source (MIT license) with full self-hosting option$q$, 0);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('0d4608fd-3411-46e9-b7bd-86e6765d726c', $q$Strong video annotation and object-tracking/interpolation tools$q$, 1);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('0d4608fd-3411-46e9-b7bd-86e6765d726c', $q$Wide dataset format support for ML pipelines$q$, 2);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('0d4608fd-3411-46e9-b7bd-86e6765d726c', $q$Active open-source community and OpenCV endorsement$q$, 3);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('0d4608fd-3411-46e9-b7bd-86e6765d726c', $q$Self-hosting requires Docker/Kubernetes infrastructure expertise$q$, 0);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('0d4608fd-3411-46e9-b7bd-86e6765d726c', $q$Learning curve for teams new to annotation workflows$q$, 1);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('0d4608fd-3411-46e9-b7bd-86e6765d726c', $q$Paid SaaS tiers add up per seat at larger team sizes$q$, 2);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('0d4608fd-3411-46e9-b7bd-86e6765d726c', $q$Enterprise self-hosted tier pricing starts fairly high$q$, 3);
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('0d4608fd-3411-46e9-b7bd-86e6765d726c', $q$Is CVAT free?$q$, $q$Yes, the self-hosted Community edition is free and open source under the MIT License. CVAT Online also offers a free tier with limited storage and tasks.$q$, 0, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('0d4608fd-3411-46e9-b7bd-86e6765d726c', $q$Can I self-host CVAT?$q$, $q$Yes, CVAT can be deployed on your own infrastructure via Docker Compose at no licensing cost.$q$, 1, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('0d4608fd-3411-46e9-b7bd-86e6765d726c', $q$What annotation types does CVAT support?$q$, $q$Bounding boxes, polygons, polylines, points, cuboids, skeletons, and 3D point-cloud annotation for images and video.$q$, 2, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('0d4608fd-3411-46e9-b7bd-86e6765d726c', $q$Does CVAT support AI-assisted labeling?$q$, $q$Yes, CVAT integrates AI and ML models for semi-automatic and automatic pre-labeling.$q$, 3, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('0d4608fd-3411-46e9-b7bd-86e6765d726c', $q$Who maintains CVAT?$q$, $q$CVAT.ai Corporation, an independent company spun out from Intel and OpenCV stewardship in 2022, maintains CVAT.$q$, 4, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('0d4608fd-3411-46e9-b7bd-86e6765d726c', $q$What's the difference between CVAT Community and CVAT Online?$q$, $q$Community is the free, self-hosted open-source edition; CVAT Online is the paid, cloud-hosted SaaS version with managed infrastructure.$q$, 5, 'published');
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('0d4608fd-3411-46e9-b7bd-86e6765d726c', $q$Autonomous vehicle and robotics training data$q$, $q$Labeling large volumes of image and video data for perception models.$q$, $q$ML engineers and data scientists$q$, 0);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('0d4608fd-3411-46e9-b7bd-86e6765d726c', $q$Medical imaging annotation$q$, $q$Self-hosting CVAT to maintain full data sovereignty over sensitive imaging data.$q$, $q$Healthcare AI teams$q$, 1);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('0d4608fd-3411-46e9-b7bd-86e6765d726c', $q$Retail and agriculture computer vision datasets$q$, $q$Annotating shelf, inventory, crop or livestock imagery for applied ML models.$q$, $q$Applied ML teams$q$, 2);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('0d4608fd-3411-46e9-b7bd-86e6765d726c', $q$Free$q$, $q$$0$q$, $q$N/A$q$, NULL, $q$["1 GB storage","1 project, 3 tasks","Image, video and 3D data support","Community support"]$q$::jsonb, 0);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('0d4608fd-3411-46e9-b7bd-86e6765d726c', $q$Solo$q$, $q$$33/month ($23/month annual)$q$, $q$Monthly or annual$q$, NULL, $q$["25 GB storage","10 projects, 250 tasks","10,000 AI agent calls/month","API access with cloud storage connections"]$q$::jsonb, 1);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('0d4608fd-3411-46e9-b7bd-86e6765d726c', $q$Team$q$, $q$$33/user/month ($23/user/month annual)$q$, $q$Monthly or annual, minimum 2 seats$q$, NULL, $q$["Up to 50 users","125 GB storage per tier level","50,000 AI agent calls/month","Reports and role-based access control"]$q$::jsonb, 2);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('0d4608fd-3411-46e9-b7bd-86e6765d726c', $q$Enterprise (Self-Hosted)$q$, $q$From $12,000/year$q$, $q$Annual$q$, NULL, $q$["Hosted within your own infrastructure","Enhanced security and compliance","Dedicated support"]$q$::jsonb, 3);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('0d4608fd-3411-46e9-b7bd-86e6765d726c', $q$overview$q$, $q$Overview$q$, 2, ARRAY[$q$CVAT began as an internal Intel tool in 2017 and was open-sourced in 2018, later spinning out into independent company CVAT.ai Corporation in 2022. It is one of the most widely adopted open-source platforms for labeling images and video for computer vision and machine learning.$q$, $q$The project offers a free, MIT-licensed, self-hostable Community edition alongside a paid CVAT Online SaaS product and an enterprise self-hosted tier with commercial support.$q$]::text[], 0);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('0d4608fd-3411-46e9-b7bd-86e6765d726c', $q$key-features$q$, $q$Key Features$q$, 2, ARRAY[$q$CVAT supports bounding boxes, polygons, polylines, points, cuboids, skeletons, and 3D point-cloud annotation, along with video interpolation and object tracking across frames, and dataset import/export in formats like COCO, YOLO and Pascal VOC.$q$, $q$AI-assisted and automatic annotation features use integrated machine learning models to pre-label data, while role-based access control and a review workflow support quality control across annotation teams.$q$]::text[], 1);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('0d4608fd-3411-46e9-b7bd-86e6765d726c', $q$pricing-overview$q$, $q$Pricing$q$, 2, ARRAY[$q$The self-hosted Community edition is free under the MIT License. CVAT Online's free tier includes 1 GB storage and up to three tasks, while the Solo plan starts around $33/month ($23/month billed annually) and the Team plan is priced per user with a two-seat minimum.$q$, $q$An Enterprise self-hosted tier starts at roughly $12,000/year, offering CVAT deployed on a customer's own infrastructure with enhanced security, compliance support and dedicated assistance.$q$]::text[], 2);
INSERT INTO tool_tag_links (tool_id, tag_id) VALUES ('0d4608fd-3411-46e9-b7bd-86e6765d726c', 'c296bd6a-c865-41d7-8807-5dce653dd3f5') ON CONFLICT DO NOTHING;
