INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('cbe1e28b-dacb-4d22-9f38-e5cc9dceeace', $q$Event Registration & Websites$q$, $q$Template-driven registration pages and event websites with payment processing.$q$, 0);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('cbe1e28b-dacb-4d22-9f38-e5cc9dceeace', $q$Onsite Check-in & Badging$q$, $q$Cvent OnArrival provides badge printing and self-service or staffed check-in kiosks.$q$, 1);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('cbe1e28b-dacb-4d22-9f38-e5cc9dceeace', $q$Webinar & Virtual Event Production$q$, $q$Studio-style virtual production tools including custom backgrounds and multi-speaker layouts.$q$, 2);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('cbe1e28b-dacb-4d22-9f38-e5cc9dceeace', $q$Venue & Hotel Sourcing Marketplace$q$, $q$The Cvent Supplier Network connects planners with venues for RFP-based sourcing.$q$, 3);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('cbe1e28b-dacb-4d22-9f38-e5cc9dceeace', $q$Attendee Engagement & Mobile App$q$, $q$Mobile event apps with networking and appointment-matching features.$q$, 4);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('cbe1e28b-dacb-4d22-9f38-e5cc9dceeace', $q$Speaker & Session Management$q$, $q$Tools for managing agendas, sessions and speakers across an event.$q$, 5);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('cbe1e28b-dacb-4d22-9f38-e5cc9dceeace', $q$Lead Retrieval & Exhibitor Management$q$, $q$Tools for exhibitors and sponsors to capture and manage leads onsite.$q$, 6);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('cbe1e28b-dacb-4d22-9f38-e5cc9dceeace', $q$CRM & Marketing Automation Integrations$q$, $q$Native integrations with Salesforce, Marketo and HubSpot for lead flow.$q$, 7);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('cbe1e28b-dacb-4d22-9f38-e5cc9dceeace', $q$All-in-one platform spanning registration, onsite, webinar and venue sourcing$q$, 0);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('cbe1e28b-dacb-4d22-9f38-e5cc9dceeace', $q$Large, established venue and hotel sourcing marketplace unmatched by most competitors$q$, 1);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('cbe1e28b-dacb-4d22-9f38-e5cc9dceeace', $q$Enterprise-grade security and compliance suited to large organizations$q$, 2);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('cbe1e28b-dacb-4d22-9f38-e5cc9dceeace', $q$Deep integrations with major CRM and marketing automation tools$q$, 3);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('cbe1e28b-dacb-4d22-9f38-e5cc9dceeace', $q$No published pricing; requires a sales engagement to get a quote$q$, 0);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('cbe1e28b-dacb-4d22-9f38-e5cc9dceeace', $q$Steeper learning curve and longer implementation than lightweight competitors$q$, 1);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('cbe1e28b-dacb-4d22-9f38-e5cc9dceeace', $q$Can be costly for small businesses or one-off event organizers$q$, 2);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('cbe1e28b-dacb-4d22-9f38-e5cc9dceeace', $q$Full feature depth may be more than infrequent or small-scale event teams need$q$, 3);
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('cbe1e28b-dacb-4d22-9f38-e5cc9dceeace', $q$What is Cvent used for?$q$, $q$Cvent is used to plan, promote and manage in-person, virtual and hybrid events, including registration, onsite check-in, webinars and venue sourcing.$q$, 0, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('cbe1e28b-dacb-4d22-9f38-e5cc9dceeace', $q$How much does Cvent cost?$q$, $q$Cvent does not publish pricing; costs are quoted based on the modules purchased and expected event volume.$q$, 1, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('cbe1e28b-dacb-4d22-9f38-e5cc9dceeace', $q$Does Cvent handle both virtual and in-person events?$q$, $q$Yes, Cvent supports in-person, virtual and hybrid events including native webinar production.$q$, 2, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('cbe1e28b-dacb-4d22-9f38-e5cc9dceeace', $q$What is the Cvent Supplier Network?$q$, $q$It is Cvent's marketplace connecting meeting planners with hotels and venues for RFP-based sourcing and bid comparison.$q$, 3, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('cbe1e28b-dacb-4d22-9f38-e5cc9dceeace', $q$Who owns Cvent?$q$, $q$Cvent is owned by Blackstone, following its 2023 take-private acquisition, with a minority investment from the Abu Dhabi Investment Authority and continued participation from Vista Equity Partners.$q$, 4, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('cbe1e28b-dacb-4d22-9f38-e5cc9dceeace', $q$What are Cvent's main alternatives?$q$, $q$Eventbrite, Bizzabo, Splash, Whova and ON24-style standalone webinar platforms are commonly compared alternatives.$q$, 5, 'published');
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('cbe1e28b-dacb-4d22-9f38-e5cc9dceeace', $q$Corporate conference & meeting management$q$, $q$Managing registration, agendas and onsite logistics for large corporate or association conferences.$q$, $q$Enterprise event marketing teams$q$, 0);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('cbe1e28b-dacb-4d22-9f38-e5cc9dceeace', $q$Hotel and venue RFP sourcing$q$, $q$Sourcing and comparing hotel and venue bids through the Cvent Supplier Network.$q$, $q$Meeting planners$q$, 1);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('cbe1e28b-dacb-4d22-9f38-e5cc9dceeace', $q$Webinar and virtual event production$q$, $q$Producing branded, studio-style webinars connected to the broader event platform.$q$, $q$Marketing and demand-generation teams$q$, 2);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('cbe1e28b-dacb-4d22-9f38-e5cc9dceeace', $q$Custom Enterprise Quote$q$, $q$Contact sales$q$, $q$Annual contract$q$, NULL, $q$["Modular pricing by product (registration, onsite, webinar, sourcing)","Volume-based on events and attendees per year","Dedicated implementation and support"]$q$::jsonb, 0);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('cbe1e28b-dacb-4d22-9f38-e5cc9dceeace', $q$overview$q$, $q$Overview$q$, 2, ARRAY[$q$Cvent is an enterprise event management platform founded in 1999 by Reggie Aggarwal and headquartered in Tysons, Virginia. It has changed ownership multiple times, including a 2023 take-private acquisition by Blackstone for approximately $4.6 billion, and now serves tens of thousands of customers with more than 5,000 employees.$q$, $q$The platform spans the full event lifecycle, from registration and websites to onsite check-in, webinars, and venue sourcing, making it one of the broadest suites in the event-technology category.$q$]::text[], 0);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('cbe1e28b-dacb-4d22-9f38-e5cc9dceeace', $q$key-features$q$, $q$Key Features$q$, 2, ARRAY[$q$Core capabilities include event registration and website creation, agenda and speaker management, and onsite check-in and badge printing through Cvent OnArrival, alongside Cvent Webinar for studio-style virtual event production.$q$, $q$The Cvent Supplier Network gives meeting planners access to a large marketplace of hotels and venues for RFP-based sourcing, while integrations with Salesforce, Marketo and HubSpot connect event data to CRM and marketing automation systems.$q$]::text[], 1);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('cbe1e28b-dacb-4d22-9f38-e5cc9dceeace', $q$pricing-overview$q$, $q$Pricing$q$, 2, ARRAY[$q$Cvent does not publish self-serve pricing. Costs are quoted based on which modules are purchased, such as event management, webinars, onsite hardware and software, or venue sourcing, and on expected event and attendee volume.$q$, $q$This sales-led, enterprise pricing model is typical for large event-technology platforms and means Cvent is generally not a fit for individuals or very small businesses running one-off events.$q$]::text[], 2);
INSERT INTO tool_tag_links (tool_id, tag_id) VALUES ('cbe1e28b-dacb-4d22-9f38-e5cc9dceeace', 'c296bd6a-c865-41d7-8807-5dce653dd3f5') ON CONFLICT DO NOTHING;
INSERT INTO tool_tag_links (tool_id, tag_id) VALUES ('cbe1e28b-dacb-4d22-9f38-e5cc9dceeace', '96595ec7-e449-4fd5-803d-e73ba922c0ca') ON CONFLICT DO NOTHING;
INSERT INTO tool_tag_links (tool_id, tag_id) VALUES ('cbe1e28b-dacb-4d22-9f38-e5cc9dceeace', '4137e3dc-5b54-4d6a-adfa-85ce8104e38f') ON CONFLICT DO NOTHING;
INSERT INTO tool_tag_links (tool_id, tag_id) VALUES ('cbe1e28b-dacb-4d22-9f38-e5cc9dceeace', '7336153f-a26b-491c-b927-faf4f5a8d103') ON CONFLICT DO NOTHING;
INSERT INTO tool_tag_links (tool_id, tag_id) VALUES ('cbe1e28b-dacb-4d22-9f38-e5cc9dceeace', '5e4d4807-cae2-410c-9e7a-df0798a917cb') ON CONFLICT DO NOTHING;
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('665b1bfd-5f00-4b50-b428-2743e447dd31', $q$Unified Multi-Account Inbox$q$, $q$Combined inbox, unread, sent and flagged views across multiple email accounts.$q$, 0);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('665b1bfd-5f00-4b50-b428-2743e447dd31', $q$RSS/Atom Feed Aggregation$q$, $q$Displays RSS and Atom feeds alongside email in the same unified views.$q$, 1);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('665b1bfd-5f00-4b50-b428-2743e447dd31', $q$Cross-Account Search$q$, $q$Fast search that queries across all connected accounts and feeds at once.$q$, 2);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('665b1bfd-5f00-4b50-b428-2743e447dd31', $q$IMAP, JMAP & EWS Protocol Support$q$, $q$Connects to traditional IMAP/SMTP servers, modern JMAP providers, and Exchange via EWS.$q$, 3);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('665b1bfd-5f00-4b50-b428-2743e447dd31', $q$Sieve Server-Side Filtering$q$, $q$Mail filtering rules that apply even when the user is not logged in.$q$, 4);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('665b1bfd-5f00-4b50-b428-2743e447dd31', $q$Plugin-Based Module Set Architecture$q$, $q$Independent plugins executed by a small core framework for extensibility.$q$, 5);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('665b1bfd-5f00-4b50-b428-2743e447dd31', $q$LDAP Directory Lookups$q$, $q$Address book and contact lookups via LDAP integration.$q$, 6);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('665b1bfd-5f00-4b50-b428-2743e447dd31', $q$Lightweight PHP/JS Footprint$q$, $q$Designed for fast performance on low-resource hosting.$q$, 7);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('665b1bfd-5f00-4b50-b428-2743e447dd31', $q$Completely free and open source (LGPL v2.1)$q$, 0);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('665b1bfd-5f00-4b50-b428-2743e447dd31', $q$Aggregates multiple email accounts, protocols and RSS feeds in one inbox$q$, 1);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('665b1bfd-5f00-4b50-b428-2743e447dd31', $q$Lightweight, fast, and low resource usage on the hosting server$q$, 2);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('665b1bfd-5f00-4b50-b428-2743e447dd31', $q$Supports modern (JMAP) and legacy (IMAP/EWS) mail protocols side by side$q$, 3);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('665b1bfd-5f00-4b50-b428-2743e447dd31', $q$No commercial support or SLA; community-maintained only$q$, 0);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('665b1bfd-5f00-4b50-b428-2743e447dd31', $q$Minimal interface with fewer built-in groupware features than Roundcube or SOGo$q$, 1);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('665b1bfd-5f00-4b50-b428-2743e447dd31', $q$Requires self-hosting and technical setup; no hosted SaaS version offered by the project itself$q$, 2);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('665b1bfd-5f00-4b50-b428-2743e447dd31', $q$Smaller contributor community than more established open-source webmail projects$q$, 3);
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('665b1bfd-5f00-4b50-b428-2743e447dd31', $q$Is Cypht free?$q$, $q$Yes, Cypht is completely free and open source under the LGPL v2.1 license.$q$, 0, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('665b1bfd-5f00-4b50-b428-2743e447dd31', $q$What email protocols does Cypht support?$q$, $q$IMAP, SMTP, JMAP and EWS (Exchange Web Services), plus RSS/Atom feed aggregation.$q$, 1, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('665b1bfd-5f00-4b50-b428-2743e447dd31', $q$Who created Cypht?$q$, $q$Cypht was created by developer Jason Munro, who previously built the Hastymail webmail projects.$q$, 2, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('665b1bfd-5f00-4b50-b428-2743e447dd31', $q$Can Cypht read RSS feeds?$q$, $q$Yes, Cypht can aggregate RSS and Atom feeds alongside email accounts in unified views.$q$, 3, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('665b1bfd-5f00-4b50-b428-2743e447dd31', $q$Is Cypht still maintained?$q$, $q$Yes; ownership shifted to a community-driven model in June 2023 and development continues on GitHub.$q$, 4, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('665b1bfd-5f00-4b50-b428-2743e447dd31', $q$What are Cypht's alternatives?$q$, $q$Roundcube, SOGo, and Rainloop are commonly compared self-hosted open-source webmail alternatives.$q$, 5, 'published');
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('665b1bfd-5f00-4b50-b428-2743e447dd31', $q$Self-hosted email for ISPs and schools$q$, $q$Providing lightweight webmail access to subscribers, students or staff.$q$, $q$Sysadmins and IT teams$q$, 0);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('665b1bfd-5f00-4b50-b428-2743e447dd31', $q$Multi-account power-user aggregation$q$, $q$Unifying several personal or work email accounts into one inbox.$q$, $q$Individuals with multiple email accounts$q$, 1);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('665b1bfd-5f00-4b50-b428-2743e447dd31', $q$Lightweight webmail on low-resource servers$q$, $q$Running a fast, low-footprint webmail client on a VPS or small server.$q$, $q$Self-hosters and VPS users$q$, 2);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('665b1bfd-5f00-4b50-b428-2743e447dd31', $q$Community$q$, $q$Free$q$, $q$N/A$q$, NULL, $q$["Self-hosted","Full source code access","Community support via GitHub"]$q$::jsonb, 0);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('665b1bfd-5f00-4b50-b428-2743e447dd31', $q$overview$q$, $q$Overview$q$, 2, ARRAY[$q$Cypht is a free, open-source webmail client created by Jason Munro, the developer behind the earlier Hastymail projects, with its first commit dating to February 2014. It is licensed under LGPL v2.1 and has been a community-driven project since June 2023.$q$, $q$Built in PHP and JavaScript, Cypht is designed to be lightweight and to unify multiple email accounts, protocols, and RSS feeds into a single inbox rather than serving as a full groupware suite.$q$]::text[], 0);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('665b1bfd-5f00-4b50-b428-2743e447dd31', $q$key-features$q$, $q$Key Features$q$, 2, ARRAY[$q$Cypht supports IMAP, SMTP, JMAP and EWS protocols simultaneously, letting one installation aggregate accounts from different backend mail systems, and can also display RSS and Atom feeds alongside email in unified views.$q$, $q$A plugin-based module-set architecture, fast cross-account search, Sieve server-side filtering, and LDAP directory lookups round out its feature set for self-hosted deployments.$q$]::text[], 1);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('665b1bfd-5f00-4b50-b428-2743e447dd31', $q$pricing-overview$q$, $q$Pricing$q$, 2, ARRAY[$q$Cypht is completely free and open source with no commercial tier. It can be self-hosted on any standard PHP-capable server at no licensing cost.$q$, $q$There is no vendor-provided hosted version; users or organizations are responsible for their own hosting and maintenance.$q$]::text[], 2);
INSERT INTO tool_tag_links (tool_id, tag_id) VALUES ('665b1bfd-5f00-4b50-b428-2743e447dd31', '326f20ae-646d-484a-96b8-335f75262ea9') ON CONFLICT DO NOTHING;
INSERT INTO tool_tag_links (tool_id, tag_id) VALUES ('665b1bfd-5f00-4b50-b428-2743e447dd31', 'efe7ced3-7cfa-4b39-9792-3427d24fa58d') ON CONFLICT DO NOTHING;
INSERT INTO tool_tag_links (tool_id, tag_id) VALUES ('665b1bfd-5f00-4b50-b428-2743e447dd31', '97eb8f3e-e378-4a5d-b2a5-331706e86e50') ON CONFLICT DO NOTHING;
INSERT INTO tool_tag_links (tool_id, tag_id) VALUES ('665b1bfd-5f00-4b50-b428-2743e447dd31', '4137e3dc-5b54-4d6a-adfa-85ce8104e38f') ON CONFLICT DO NOTHING;
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('8e2764a7-0bfa-42fa-913d-469e0d66e4ce', $q$IMAP/IMAPS, POP3/POP3S & JMAP Support$q$, $q$Supports legacy and modern mail access protocols, including Fastmail-driven JMAP development.$q$, 0);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('8e2764a7-0bfa-42fa-913d-469e0d66e4ce', $q$CalDAV & CardDAV$q$, $q$Native calendar and contacts support alongside email.$q$, 1);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('8e2764a7-0bfa-42fa-913d-469e0d66e4ce', $q$Sieve Server-Side Filtering$q$, $q$Standardized mail filtering that applies even when the client is offline.$q$, 2);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('8e2764a7-0bfa-42fa-913d-469e0d66e4ce', $q$Mailbox Access Control Lists$q$, $q$Fine-grained sharing and delegation permissions on individual mailboxes.$q$, 3);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('8e2764a7-0bfa-42fa-913d-469e0d66e4ce', $q$Storage Quotas$q$, $q$Per-user and per-hierarchy quota enforcement.$q$, 4);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('8e2764a7-0bfa-42fa-913d-469e0d66e4ce', $q$Sealed-Server Security Architecture$q$, $q$End users never get shell access to the mail server, improving security.$q$, 5);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('8e2764a7-0bfa-42fa-913d-469e0d66e4ce', $q$Large-Scale Mail Store$q$, $q$Optimized internal storage format built for very large institutional deployments.$q$, 6);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('8e2764a7-0bfa-42fa-913d-469e0d66e4ce', $q$Active JMAP Development$q$, $q$Ongoing investment in the modern JMAP protocol in partnership with Fastmail.$q$, 7);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('8e2764a7-0bfa-42fa-913d-469e0d66e4ce', $q$Free, open source, and proven at large institutional scale for decades$q$, 0);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('8e2764a7-0bfa-42fa-913d-469e0d66e4ce', $q$Native calendar and contacts (CalDAV/CardDAV) support beyond just email$q$, 1);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('8e2764a7-0bfa-42fa-913d-469e0d66e4ce', $q$Strong security model via sealed-server architecture$q$, 2);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('8e2764a7-0bfa-42fa-913d-469e0d66e4ce', $q$Actively maintained with modern JMAP protocol investment via Fastmail$q$, 3);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('8e2764a7-0bfa-42fa-913d-469e0d66e4ce', $q$Steep setup and administration learning curve; not beginner friendly$q$, 0);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('8e2764a7-0bfa-42fa-913d-469e0d66e4ce', $q$No built-in web interface; requires a separate webmail client$q$, 1);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('8e2764a7-0bfa-42fa-913d-469e0d66e4ce', $q$Smaller self-hosting community than Dovecot for small deployments$q$, 2);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('8e2764a7-0bfa-42fa-913d-469e0d66e4ce', $q$Internal mail-store format is less portable than standard Maildir/mbox$q$, 3);
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('8e2764a7-0bfa-42fa-913d-469e0d66e4ce', $q$Is Cyrus IMAP free?$q$, $q$Yes, Cyrus IMAP is free and open source under a BSD-style license.$q$, 0, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('8e2764a7-0bfa-42fa-913d-469e0d66e4ce', $q$Who maintains Cyrus IMAP?$q$, $q$Carnegie Mellon University originated and continues to host the project, while Fastmail engineers drive much of the modern development.$q$, 1, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('8e2764a7-0bfa-42fa-913d-469e0d66e4ce', $q$Does Cyrus IMAP support calendars and contacts?$q$, $q$Yes, via native CalDAV and CardDAV support alongside email.$q$, 2, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('8e2764a7-0bfa-42fa-913d-469e0d66e4ce', $q$What's the difference between Cyrus IMAP and Dovecot?$q$, $q$Cyrus uses a sealed-server model geared toward large institutional deployments, while Dovecot is generally easier to configure and more common in small-to-mid-size self-hosted setups.$q$, 3, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('8e2764a7-0bfa-42fa-913d-469e0d66e4ce', $q$Does Cyrus support JMAP?$q$, $q$Yes, Cyrus has ongoing active development of the JMAP protocol, co-driven by Fastmail.$q$, 4, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('8e2764a7-0bfa-42fa-913d-469e0d66e4ce', $q$Who uses Cyrus IMAP?$q$, $q$Universities, ISPs and enterprises that need to self-host mail infrastructure at scale, including Carnegie Mellon University and Fastmail.$q$, 5, 'published');
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('8e2764a7-0bfa-42fa-913d-469e0d66e4ce', $q$University email infrastructure$q$, $q$Running large-scale, centrally managed mail for students and staff.$q$, $q$University IT departments$q$, 0);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('8e2764a7-0bfa-42fa-913d-469e0d66e4ce', $q$ISP-scale hosted mail backend$q$, $q$Powering commercial hosted email services at scale.$q$, $q$Email hosting providers$q$, 1);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('8e2764a7-0bfa-42fa-913d-469e0d66e4ce', $q$Self-hosted groupware$q$, $q$Running mail, calendar and contacts together on owned infrastructure.$q$, $q$Enterprise sysadmins$q$, 2);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('8e2764a7-0bfa-42fa-913d-469e0d66e4ce', $q$Community$q$, $q$Free$q$, $q$N/A$q$, NULL, $q$["Self-hosted","Full source code access","Community and Fastmail-driven development"]$q$::jsonb, 0);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('8e2764a7-0bfa-42fa-913d-469e0d66e4ce', $q$overview$q$, $q$Overview$q$, 2, ARRAY[$q$Cyrus IMAP is a free, open-source mail server originating at Carnegie Mellon University in the early-to-mid 1990s, still hosted and governed there today, with the bulk of modern development driven by engineers at Fastmail, which uses Cyrus as its own commercial email backend.$q$, $q$It provides email, calendar (CalDAV) and contacts (CardDAV) service through a sealed-server security architecture, functioning as a self-hosted groupware backend comparable in scope to Microsoft Exchange.$q$]::text[], 0);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('8e2764a7-0bfa-42fa-913d-469e0d66e4ce', $q$key-features$q$, $q$Key Features$q$, 2, ARRAY[$q$Cyrus supports IMAP, IMAPS, POP3, POP3S, KPOP and the modern JMAP protocol, along with native Sieve server-side filtering, mailbox access control lists, and per-user storage quotas.$q$, $q$Built-in CalDAV and CardDAV support lets Cyrus serve as a full calendar and contacts backend alongside email, distinguishing it from pure IMAP servers.$q$]::text[], 1);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('8e2764a7-0bfa-42fa-913d-469e0d66e4ce', $q$pricing-overview$q$, $q$Pricing$q$, 2, ARRAY[$q$Cyrus IMAP is free and open source under a BSD-style license, with no commercial pricing plans. Organizations bear only their own infrastructure and systems-administration costs.$q$, $q$There is no vendor selling Cyrus licenses; Fastmail contributes engineering time as a user of the software for its own hosted email service.$q$]::text[], 2);
INSERT INTO tool_tag_links (tool_id, tag_id) VALUES ('8e2764a7-0bfa-42fa-913d-469e0d66e4ce', '326f20ae-646d-484a-96b8-335f75262ea9') ON CONFLICT DO NOTHING;
INSERT INTO tool_tag_links (tool_id, tag_id) VALUES ('8e2764a7-0bfa-42fa-913d-469e0d66e4ce', 'efe7ced3-7cfa-4b39-9792-3427d24fa58d') ON CONFLICT DO NOTHING;
INSERT INTO tool_tag_links (tool_id, tag_id) VALUES ('8e2764a7-0bfa-42fa-913d-469e0d66e4ce', '97eb8f3e-e378-4a5d-b2a5-331706e86e50') ON CONFLICT DO NOTHING;
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('4e2e35d0-4b3f-44fd-9859-4de0cee91c3f', $q$Photo-to-Talking-Avatar Video Generation$q$, $q$Turns a single photo into a lip-synced talking avatar video.$q$, 0);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('4e2e35d0-4b3f-44fd-9859-4de0cee91c3f', $q$Text-to-Speech in 120+ Languages$q$, $q$Generates natural-sounding voiceover in a wide range of languages and accents.$q$, 1);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('4e2e35d0-4b3f-44fd-9859-4de0cee91c3f', $q$Custom Voice Cloning$q$, $q$Clones a specific voice for use across generated avatar videos.$q$, 2);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('4e2e35d0-4b3f-44fd-9859-4de0cee91c3f', $q$D-ID Agents$q$, $q$Real-time, interactive conversational avatars connected to an LLM backend.$q$, 3);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('4e2e35d0-4b3f-44fd-9859-4de0cee91c3f', $q$Stock Avatar Library$q$, $q$Pre-built presenter avatars for users without their own photo assets.$q$, 4);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('4e2e35d0-4b3f-44fd-9859-4de0cee91c3f', $q$Developer REST API$q$, $q$Programmatic access to avatar and video generation for custom integrations.$q$, 5);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('4e2e35d0-4b3f-44fd-9859-4de0cee91c3f', $q$Multi-Language Localization$q$, $q$Supports localized training and marketing video production at scale.$q$, 6);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('4e2e35d0-4b3f-44fd-9859-4de0cee91c3f', $q$LLM Integration$q$, $q$Connects to D-ID's own or third-party large language models for interactive agents.$q$, 7);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('4e2e35d0-4b3f-44fd-9859-4de0cee91c3f', $q$Fast, low-cost way to create talking-avatar video without filming$q$, 0);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('4e2e35d0-4b3f-44fd-9859-4de0cee91c3f', $q$Supports 120+ languages and accents for global content localization$q$, 1);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('4e2e35d0-4b3f-44fd-9859-4de0cee91c3f', $q$Both no-code Studio and developer API options available$q$, 2);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('4e2e35d0-4b3f-44fd-9859-4de0cee91c3f', $q$Real-time conversational Agents product for interactive use cases$q$, 3);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('4e2e35d0-4b3f-44fd-9859-4de0cee91c3f', $q$Avatar realism and lip-sync can lag top competitors like Synthesia and HeyGen on close inspection$q$, 0);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('4e2e35d0-4b3f-44fd-9859-4de0cee91c3f', $q$Lower-tier plans include watermarks and limited monthly video minutes$q$, 1);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('4e2e35d0-4b3f-44fd-9859-4de0cee91c3f', $q$Advanced features such as voice cloning and full Agents functionality require higher-priced tiers$q$, 2);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('4e2e35d0-4b3f-44fd-9859-4de0cee91c3f', $q$Enterprise pricing is custom and not published$q$, 3);
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('4e2e35d0-4b3f-44fd-9859-4de0cee91c3f', $q$What is D-ID used for?$q$, $q$D-ID is used to create talking-avatar videos from photos and scripts, and to power real-time interactive AI avatars for customer service and sales.$q$, 0, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('4e2e35d0-4b3f-44fd-9859-4de0cee91c3f', $q$How much does D-ID cost?$q$, $q$Studio plans start around $5.99/month (Lite) and scale to Pro (~$49.99/month) and Advanced (~$299.99/month), with custom Enterprise pricing available.$q$, 1, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('4e2e35d0-4b3f-44fd-9859-4de0cee91c3f', $q$Does D-ID offer a free trial?$q$, $q$Yes, D-ID typically offers a free trial period on its Studio plans.$q$, 2, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('4e2e35d0-4b3f-44fd-9859-4de0cee91c3f', $q$What languages does D-ID support?$q$, $q$D-ID supports text-to-speech avatar generation in more than 120 languages and accents.$q$, 3, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('4e2e35d0-4b3f-44fd-9859-4de0cee91c3f', $q$What is the difference between D-ID Studio and D-ID Agents?$q$, $q$Studio creates pre-recorded avatar videos from scripts or audio, while Agents powers real-time, interactive conversational avatars.$q$, 4, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('4e2e35d0-4b3f-44fd-9859-4de0cee91c3f', $q$What are D-ID's main competitors?$q$, $q$Synthesia and HeyGen are the most commonly compared AI avatar and video generation competitors.$q$, 5, 'published');
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('4e2e35d0-4b3f-44fd-9859-4de0cee91c3f', $q$Corporate training and e-learning localization$q$, $q$Producing multi-language instructor avatar videos for training content.$q$, $q$L&D teams and course creators$q$, 0);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('4e2e35d0-4b3f-44fd-9859-4de0cee91c3f', $q$Marketing and explainer video production$q$, $q$Creating avatar-led marketing or explainer videos without filming.$q$, $q$Marketing teams$q$, 1);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('4e2e35d0-4b3f-44fd-9859-4de0cee91c3f', $q$Interactive customer-facing AI avatars$q$, $q$Deploying real-time conversational avatars for support or sales interactions.$q$, $q$Customer service and sales teams$q$, 2);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('4e2e35d0-4b3f-44fd-9859-4de0cee91c3f', $q$Lite$q$, $q$$5.99/month$q$, $q$Monthly$q$, NULL, $q$["10 minutes of video/month","Watermarked output"]$q$::jsonb, 0);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('4e2e35d0-4b3f-44fd-9859-4de0cee91c3f', $q$Pro$q$, $q$$49.99/month$q$, $q$Monthly$q$, NULL, $q$["15 minutes of video/month","Premium avatars","API access"]$q$::jsonb, 1);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('4e2e35d0-4b3f-44fd-9859-4de0cee91c3f', $q$Advanced$q$, $q$$299.99/month$q$, $q$Monthly$q$, NULL, $q$["65 minutes of video/month","Voice cloning","Full feature access"]$q$::jsonb, 2);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('4e2e35d0-4b3f-44fd-9859-4de0cee91c3f', $q$Enterprise$q$, $q$Custom$q$, $q$Custom$q$, NULL, $q$["Unlimited customization","Dedicated support","Volume/seat-based contracts"]$q$::jsonb, 3);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('4e2e35d0-4b3f-44fd-9859-4de0cee91c3f', $q$overview$q$, $q$Overview$q$, 2, ARRAY[$q$D-ID is an AI video generation company founded in 2017 in Tel Aviv by Gil Perry and co-founders, originally built around photo de-identification technology before pivoting into talking-avatar video generation. It has raised roughly $48 million in funding and acquired explainer-video company simpleshow in September 2025.$q$, $q$The company's technology turns a single photo plus a script or audio recording into a photorealistic talking-avatar video, and also powers real-time interactive AI avatars through its Agents product.$q$]::text[], 0);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('4e2e35d0-4b3f-44fd-9859-4de0cee91c3f', $q$key-features$q$, $q$Key Features$q$, 2, ARRAY[$q$Creative Reality Studio lets users generate pre-recorded avatar videos with text-to-speech in more than 120 languages and accents, custom voice cloning, and a library of stock presenter avatars, accessible via a no-code web studio or developer API.$q$, $q$D-ID Agents extends the technology to real-time, interactive conversational avatars that can be embedded on websites or apps and connected to a large language model backend for live customer service or sales conversations.$q$]::text[], 1);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('4e2e35d0-4b3f-44fd-9859-4de0cee91c3f', $q$pricing-overview$q$, $q$Pricing$q$, 2, ARRAY[$q$Studio plans start with Lite at about $5.99/month for 10 minutes of video, scaling to Pro at about $49.99/month and Advanced at about $299.99/month with more minutes, voice cloning and full feature access.$q$, $q$An Enterprise tier offers custom pricing with unlimited customization and dedicated support, while D-ID also charges separately for metered API usage on its developer platform.$q$]::text[], 2);
INSERT INTO tool_tag_links (tool_id, tag_id) VALUES ('4e2e35d0-4b3f-44fd-9859-4de0cee91c3f', 'c296bd6a-c865-41d7-8807-5dce653dd3f5') ON CONFLICT DO NOTHING;
