INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('8f5095fd-2fe0-49e0-936e-9bb82f1c6752', $q$Declarative Text-to-Diagram Syntax$q$, $q$Describe diagram elements and relationships in plain text; layout is handled automatically.$q$, 0);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('8f5095fd-2fe0-49e0-936e-9bb82f1c6752', $q$Multiple Auto-Layout Engines$q$, $q$Choose between dagre and ELK-based layout engines depending on diagram complexity.$q$, 1);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('8f5095fd-2fe0-49e0-936e-9bb82f1c6752', $q$Architecture-Focused Shape Library$q$, $q$Shapes like cylinders, queues, clouds and person icons tuned for technical diagrams.$q$, 2);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('8f5095fd-2fe0-49e0-936e-9bb82f1c6752', $q$Built-in Themes$q$, $q$Official visual themes, including dark-mode options, for consistent styling.$q$, 3);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('8f5095fd-2fe0-49e0-936e-9bb82f1c6752', $q$Git-Friendly Plain-Text Files$q$, $q$Diagrams stored as text can be version-controlled, diffed and code-reviewed.$q$, 4);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('8f5095fd-2fe0-49e0-936e-9bb82f1c6752', $q$CLI & Server-Side Rendering$q$, $q$Compile diagrams via command line or run D2 as a server-side rendering service.$q$, 5);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('8f5095fd-2fe0-49e0-936e-9bb82f1c6752', $q$Autoformatter & Multi-Error Parser$q$, $q$Consistent formatting and clear error reporting across a broken diagram file.$q$, 6);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('8f5095fd-2fe0-49e0-936e-9bb82f1c6752', $q$Editor Integrations$q$, $q$Official VS Code extension plus community integrations for Vim, Obsidian, Slack and Discord.$q$, 7);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('8f5095fd-2fe0-49e0-936e-9bb82f1c6752', $q$Completely free and open source (MPL-2.0)$q$, 0);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('8f5095fd-2fe0-49e0-936e-9bb82f1c6752', $q$Diagrams stored as plain text, ideal for Git version control and code review$q$, 1);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('8f5095fd-2fe0-49e0-936e-9bb82f1c6752', $q$Purpose-built shape library and layout for software architecture diagrams$q$, 2);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('8f5095fd-2fe0-49e0-936e-9bb82f1c6752', $q$Active open-source community and growing ecosystem of integrations$q$, 3);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('8f5095fd-2fe0-49e0-936e-9bb82f1c6752', $q$Newer and less pre-integrated into platforms like GitHub or Notion than Mermaid$q$, 0);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('8f5095fd-2fe0-49e0-936e-9bb82f1c6752', $q$Requires learning a diagram-specific syntax rather than pure drag-and-drop$q$, 1);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('8f5095fd-2fe0-49e0-936e-9bb82f1c6752', $q$Advanced visual and collaborative editing requires Terrastruct's separate paid app$q$, 2);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('8f5095fd-2fe0-49e0-936e-9bb82f1c6752', $q$Auto-layout engines can require manual tuning for very complex diagrams$q$, 3);
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('8f5095fd-2fe0-49e0-936e-9bb82f1c6752', $q$Is D2 free?$q$, $q$Yes, the D2 language and command-line tool are free and open source under the Mozilla Public License 2.0.$q$, 0, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('8f5095fd-2fe0-49e0-936e-9bb82f1c6752', $q$Who created D2?$q$, $q$D2 was created by Terrastruct, a San Francisco-based company founded in 2019 by Alexander Wang.$q$, 1, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('8f5095fd-2fe0-49e0-936e-9bb82f1c6752', $q$What license is D2 released under?$q$, $q$D2 is licensed under the Mozilla Public License 2.0 (MPL-2.0).$q$, 2, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('8f5095fd-2fe0-49e0-936e-9bb82f1c6752', $q$How is D2 different from Mermaid?$q$, $q$D2 offers a more customizable visual output and an architecture-focused shape library, while Mermaid has broader native integration into platforms like GitHub and Notion.$q$, 3, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('8f5095fd-2fe0-49e0-936e-9bb82f1c6752', $q$Can I use D2 without installing anything?$q$, $q$Yes, D2 can be used via Terrastruct's hosted playground or editor, though the CLI tool can also be installed for local use.$q$, 4, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('8f5095fd-2fe0-49e0-936e-9bb82f1c6752', $q$Does Terrastruct sell a paid product built on D2?$q$, $q$Yes, Terrastruct offers a separate paid diagramming application with visual editing and collaboration features built around the D2 language.$q$, 5, 'published');
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('8f5095fd-2fe0-49e0-936e-9bb82f1c6752', $q$Software architecture documentation-as-code$q$, $q$Maintaining architecture diagrams as version-controlled text alongside source code.$q$, $q$Engineering and platform teams$q$, 0);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('8f5095fd-2fe0-49e0-936e-9bb82f1c6752', $q$Auto-generated database ER diagrams$q$, $q$Generating entity-relationship diagrams directly from a live database schema.$q$, $q$Backend developers and DBAs$q$, 1);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('8f5095fd-2fe0-49e0-936e-9bb82f1c6752', $q$Technical diagrams in internal docs$q$, $q$Embedding rendered D2 diagrams into wikis and internal documentation sites.$q$, $q$Technical writers$q$, 2);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('8f5095fd-2fe0-49e0-936e-9bb82f1c6752', $q$D2 (Open Source)$q$, $q$Free$q$, $q$N/A$q$, NULL, $q$["Full CLI and language access","MPL-2.0 licensed","Community support via GitHub"]$q$::jsonb, 0);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('8f5095fd-2fe0-49e0-936e-9bb82f1c6752', $q$overview$q$, $q$Overview$q$, 2, ARRAY[$q$D2 is an open-source declarative diagram scripting language created by Terrastruct, a San Francisco company founded in 2019 by Alexander Wang. Terrastruct open-sourced D2 in November 2022 under the Mozilla Public License 2.0.$q$, $q$D2 lets users describe diagrams as plain text, which an automatic layout engine then renders as SVG, PNG or PDF, making it part of the growing diagrams-as-code category alongside Mermaid and PlantUML.$q$]::text[], 0);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('8f5095fd-2fe0-49e0-936e-9bb82f1c6752', $q$key-features$q$, $q$Key Features$q$, 2, ARRAY[$q$D2 offers multiple auto-layout engines, including dagre and an ELK-based engine, a shape library tuned for software architecture (cylinders, queues, clouds, person icons), and several built-in visual themes including dark mode.$q$, $q$Because diagrams are plain text files, they can be stored in Git, diffed, and code-reviewed like any other source file, with tooling including an autoformatter, multi-error parser, syntax highlighting, and editor integrations for VS Code, Vim and Obsidian.$q$]::text[], 1);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('8f5095fd-2fe0-49e0-936e-9bb82f1c6752', $q$pricing-overview$q$, $q$Pricing$q$, 2, ARRAY[$q$The D2 language and command-line compiler are entirely free and open source, with no cost to download, run, or embed in personal or commercial projects.$q$, $q$Terrastruct's revenue comes from a separate paid diagramming application built around D2 that adds visual editing and real-time collaboration for teams, funding continued development of the open-source language.$q$]::text[], 2);
INSERT INTO tool_tag_links (tool_id, tag_id) VALUES ('8f5095fd-2fe0-49e0-936e-9bb82f1c6752', '326f20ae-646d-484a-96b8-335f75262ea9') ON CONFLICT DO NOTHING;
